class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        unordered_map<string, int> seqCount;
        vector<string> result;
        for (int i = 0; i <= s.size() - 10; ++i) {
            string sub = s.substr(i, 10);
            seqCount[sub]++;
            if (seqCount[sub] == 2) {
                result.push_back(sub);
            }
        }
        return result;
    }
};
